import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Login() {
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await login(form);
      toast.success('Welcome back!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: '#eef7f1',
      padding: 20
    }}>
      <div style={{ width: '100%', maxWidth: 420 }}>

        {/* LOGO */}
        <div style={{ textAlign: 'center', marginBottom: 30 }}>
          <h1 style={{
            fontSize: 38,
            fontWeight: '800',
            color: '#16a34a'
          }}>
            ⚡ TeamTask
          </h1>

          <p style={{ color: '#6b7280', fontSize: 14 }}>
            Smart Team Management Platform
          </p>
        </div>

        {/* CARD */}
        <div style={{
          background: '#fff',
          padding: 30,
          borderRadius: 16,
          boxShadow: '0 10px 30px rgba(0,0,0,0.08)'
        }}>

          <h2 style={{
            textAlign: 'center',
            marginBottom: 20,
            fontSize: 22,
            fontWeight: '600'
          }}>
            Welcome Back 👋
          </h2>

          <form onSubmit={handleSubmit}>

            <div style={{ marginBottom: 15 }}>
              <label style={{ fontSize: 13 }}>Email</label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '12px',
                  marginTop: 5,
                  borderRadius: 8,
                  border: '1px solid #d1d5db',
                  fontSize: 14
                }}
              />
            </div>

            <div style={{ marginBottom: 20 }}>
              <label style={{ fontSize: 13 }}>Password</label>
              <input
                type="password"
                placeholder="••••••••"
                value={form.password}
                onChange={e => setForm({ ...form, password: e.target.value })}
                required
                style={{
                  width: '100%',
                  padding: '12px',
                  marginTop: 5,
                  borderRadius: 8,
                  border: '1px solid #d1d5db',
                  fontSize: 14
                }}
              />
            </div>

            <button
              type="submit"
              disabled={loading}
              style={{
                width: '100%',
                padding: '12px',
                borderRadius: 8,
                border: 'none',
                background: '#22c55e',
                color: '#fff',
                fontWeight: '600',
                cursor: 'pointer'
              }}
            >
              {loading ? 'Signing in...' : 'Sign In →'}
            </button>

          </form>

          <p style={{
            textAlign: 'center',
            marginTop: 15,
            fontSize: 13,
            color: '#6b7280'
          }}>
            No account? <Link to="/register" style={{ color: '#16a34a' }}>Register here</Link>
          </p>
        </div>

        {/* INFO */}
        <div style={{
          marginTop: 20,
          padding: 12,
          background: '#dcfce7',
          borderRadius: 10,
          fontSize: 12,
          color: '#065f46'
        }}>
          💡 Register as <b>admin</b> to create tasks <br />
          Register as <b>member</b> to submit tasks
        </div>

      </div>
    </div>
  );
}
